## 🐛 Bug Report

<!-- A clear and concise description of what the bug is. -->

Lib version: 4.4.0

## Steps To Reproduce

<!-- The exact steps required to reproduce the issue, ideally with a code example -->

```javascript
// Filename: generate_xlsx_low_memory.js
const ExcelJS = require("exceljs");
const fs = require("fs");
const path = require("path");

const numRows = 1000000;
const numCols = 100;
const outputFilename = "large_file_exceljs_stream.xlsx";
const outputDir = path.join(__dirname, "output"); // Create an output directory

async function generateLargeXlsxStream() {
  console.log(
    `Starting generation of ${outputFilename} (${numRows}x${numCols}) using exceljs stream...`
  );
  console.info(
    "INFO: This method uses streaming and should have low memory usage."
  );

  if (!fs.existsSync(outputDir)) {
    fs.mkdirSync(outputDir, { recursive: true });
    console.log(`Created output directory: ${outputDir}`);
  }
  const outputPath = path.join(outputDir, outputFilename);

  const startTime = Date.now();
  let peakMemory = 0; // Monitor memory

  const options = {
    useStyles: false, // Skip styles for performance/memory
    useSharedStrings: false, // Often better for memory with repetitive text
    stream: fs.createWriteStream(outputPath, { flags: "w" }), // Stream to file
  };

  const workbookWriter = new ExcelJS.stream.xlsx.WorkbookWriter(options);

  try {
    const worksheet = workbookWriter.addWorksheet("LargeDataSheet");

    // Add Header Row
    const header = [];
    for (let c = 0; c < numCols; c++) {
      header.push(`Column ${c + 1}`);
    }
    worksheet.addRow(header).commit(); // Commit header row

    // Add Data Rows and Commit frequently
    console.log("Generating and streaming data rows...");
    for (let r = 0; r < numRows; r++) {
      const rowData = [];
      for (let c = 0; c < numCols; c++) {
        // Simple data
        rowData.push(`R${r + 1}C${c + 1}`);
      }
      worksheet.addRow(rowData).commit(); // Add row and COMMIT it to the stream
      // Optional: Log progress and memory periodically
      if ((r + 1) % 10000 === 0) {
        // Log every 10k rows
        // THIS HELPS !!!
        // await new Promise((resolve) => setTimeout(resolve, 1000));
        const currentMemory = process.memoryUsage().rss / (1024 * 1024); // MB
        peakMemory = Math.max(peakMemory, currentMemory);
        console.log(
          `  Processed ${r + 1} rows... Memory usage: ${currentMemory.toFixed(
            2
          )} MB (Peak: ${peakMemory.toFixed(2)} MB)`
        );
      }
    }

    // Crucial: Finalize the workbook writing process
    await workbookWriter.commit();

    const endTime = Date.now();
    const duration = (endTime - startTime) / 1000; // seconds
    const finalMemory = process.memoryUsage().rss / (1024 * 1024);
    peakMemory = Math.max(peakMemory, finalMemory);

    console.log("--------------------------------------------------");
    console.log(`SUCCESS: File '${outputPath}' created using exceljs stream.`);
    console.log(`Dimensions: ${numRows} rows x ${numCols} columns`);
    console.log(`Time taken: ${duration.toFixed(2)} seconds`);
    console.log(
      `Peak memory usage during script: ~${peakMemory.toFixed(2)} MB`
    );
    console.log("--------------------------------------------------");
  } catch (error) {
    console.error("--------------------------------------------------");
    console.error("ERROR generating XLSX file via stream:", error);
    const finalMemory = process.memoryUsage().rss / (1024 * 1024);
    peakMemory = Math.max(peakMemory, finalMemory);
    console.error(
      `Peak memory usage before error: ~${peakMemory.toFixed(2)} MB`
    );
    console.error("--------------------------------------------------");
    // Attempt to remove potentially corrupted file
    try {
      if (fs.existsSync(outputPath)) {
        fs.unlinkSync(outputPath);
        console.warn(`Removed potentially incomplete file: ${outputPath}`);
      }
    } catch (cleanupError) {
      console.error(`Error removing incomplete file: ${cleanupError.message}`);
    }
  }
}

generateLargeXlsxStream();

```

## The expected behaviour:

<!-- A clear and concise description of what you expected to happen. -->
Why do memory leaks happen?

## Possible solution (optional, but very helpful):

```javascript
// If I add a 1s timeout after every 10k rows, it cleans memory and works as expected.
await new Promise((resolve) => setTimeout(resolve, 1000));
```

