```typescript
import { Worksheet } from 'exceljs';

const MAX_BUFFER_SIZE = 50;
const MAX_BUFFER_SIZE_THRESHOLD = 10;

interface WorksheetWithStream extends Worksheet {
  _stream: {
    pipes: {
      _writableState: {
        bufferedRequestCount: number;
      };
    }[];
  };
}

export async function waitForStreamDrainExcel(sheet: Worksheet): Promise<void> {
  const worksheet = sheet as WorksheetWithStream;
  if (!worksheet._stream?.pipes?.[0]?._writableState) {
    console.error('Exceljs API changed. Please update the code.');
    return;
  }

  if (worksheet._stream.pipes[0]._writableState.bufferedRequestCount > MAX_BUFFER_SIZE) {
    while (worksheet._stream.pipes[0]._writableState.bufferedRequestCount > MAX_BUFFER_SIZE_THRESHOLD) {
      await new Promise((resolve) => setTimeout(resolve, 1));
    }
  }
}
```

Call this `await waitForStreamDrainExcel(sheet)` function periodically. I call it every 1000 rows, for example.
